#include<bits/stdc++.h>
using namespace std;
long long f[1000010],s[1000010];
long long n,a,b,c,q[1000010];
long long x(long long v)
{
    return s[v];
}
long long y(long long v)
{
    return (f[v]+a*s[v]*s[v]-b*s[v]);
}
long long k(long long v)
{
    return 2ll*a*s[v];
}
double xielv(long long i,long long j)
{
    return 1.0*(y(i)-y(j))/(x(i)-x(j));
}
int main()
{
    scanf("%lld%lld%lld%lld",&n,&a,&b,&c);
    for(long long i=1;i<=n;i++)
    {
        long long x;
        scanf("%lld",&x);
        s[i]=s[i-1]+x;
    }
    long long head=0,tail=0;
    for(long long i=1;i<=n;i++)
    {
        while(head<tail&&xielv(q[head],q[head+1])>k(i))
        {
            head++;
        }
        f[i]=-(k(i)*x(q[head])-y(q[head])-a*s[i]*s[i]-b*s[i]-c);
        while(head<tail&&xielv(q[tail-1],q[tail])<=xielv(q[tail],i))
        {
            tail--;
        }
        q[++tail]=i;
    }
    printf("%lld",f[n]);
    return 0;
}
